/* IOR Shared Header/Footer Loader — do not edit this file directly.
   Edit _includes/ior-header.html and _includes/ior-footer.html instead. */
(function() {
  // Resolve path to _includes relative to current page
  var base = (function() {
    var path = window.location.pathname;
    // Count directory depth from repo root (GitHub Pages serves from root)
    var parts = path.split('/').filter(Boolean);
    // Remove the filename
    parts.pop();
    // For each directory level, go up one
    var prefix = parts.length > 0 ? parts.map(function() { return '..'; }).join('/') + '/' : './';
    // Special case: if we're at root level (e.g. /ior-prototype-v3-5/page.html)
    // GitHub Pages has a repo prefix — detect by checking if path has 2+ segments
    return prefix;
  })();

  function loadInclude(url, targetId, position) {
    var el = document.getElementById(targetId);
    if (!el) return;
    fetch(url)
      .then(function(r) { return r.text(); })
      .then(function(html) {
        el.outerHTML = html;
        // Re-init nav JS after header is injected
        if (targetId === 'ior-header-include') {
          initNav();
        }
      })
      .catch(function(e) { console.warn('IOR include failed:', url, e); });
  }

  // Use absolute path from repo root for GitHub Pages
  var repoRoot = (function() {
    var m = window.location.pathname.match(/^(\/[^\/]+\/)/);
    return m ? m[1] : '/';
  })();

  loadInclude(repoRoot + '_includes/ior-header.html', 'ior-header-include');
  loadInclude(repoRoot + '_includes/ior-footer.html', 'ior-footer-include');

  function initNav() {
    // Mega menu toggle
    document.querySelectorAll('.nav-link').forEach(function(btn) {
      btn.addEventListener('click', function(e) {
        var menuId = 'mega-' + btn.dataset.menu;
        var panel = document.getElementById(menuId);
        if (!panel) return;
        var isOpen = panel.classList.contains('mega-panel--open');
        document.querySelectorAll('.mega-panel').forEach(function(p) {
          p.classList.remove('mega-panel--open');
        });
        document.querySelectorAll('.nav-link').forEach(function(b) {
          b.setAttribute('aria-expanded', 'false');
        });
        if (!isOpen) {
          panel.classList.add('mega-panel--open');
          btn.setAttribute('aria-expanded', 'true');
        }
        e.stopPropagation();
      });
    });
    // Close on outside click
    document.addEventListener('click', function() {
      document.querySelectorAll('.mega-panel').forEach(function(p) {
        p.classList.remove('mega-panel--open');
      });
      document.querySelectorAll('.nav-link').forEach(function(b) {
        b.setAttribute('aria-expanded', 'false');
      });
    });
    // Mobile drawer
    var hamburger = document.getElementById('hamburger-btn');
    var drawer = document.getElementById('mobile-drawer');
    var overlay = document.getElementById('drawer-overlay');
    function openDrawer() {
      if (!drawer) return;
      drawer.classList.add('drawer--open');
      if (overlay) overlay.classList.add('drawer-overlay--open');
      if (hamburger) hamburger.setAttribute('aria-expanded', 'true');
      drawer.removeAttribute('aria-hidden');
    }
    function closeDrawer() {
      if (!drawer) return;
      drawer.classList.remove('drawer--open');
      if (overlay) overlay.classList.remove('drawer-overlay--open');
      if (hamburger) hamburger.setAttribute('aria-expanded', 'false');
      drawer.setAttribute('aria-hidden', 'true');
    }
    if (hamburger) hamburger.addEventListener('click', openDrawer);
    if (overlay) overlay.addEventListener('click', closeDrawer);
    var closeBtn = document.getElementById('drawer-close');
    if (closeBtn) closeBtn.addEventListener('click', closeDrawer);
    // Accordion sub-menus in drawer
    document.querySelectorAll('.drawer__link').forEach(function(link) {
      link.addEventListener('click', function() {
        var item = link.closest('.drawer__item');
        if (!item) return;
        var sub = item.querySelector('.drawer__sub');
        var chevron = link.querySelector('.drawer__link-chevron');
        if (!sub) return;
        sub.classList.toggle('drawer__sub--open');
        if (chevron) chevron.classList.toggle('drawer__link-chevron--open');
      });
    });
  }
})();
